schema:
CREATE TABLE people (
    id   INT PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE folders (
    id   INT PRIMARY KEY,
    name TEXT NOT NULL
);

CREATE TABLE files (
    id        INT PRIMARY KEY,
    name      TEXT NOT NULL,
    owner_id  INT REFERENCES people(id),
    folder_id INT REFERENCES folders(id)
);

CREATE TABLE file_access (
    file_id   INT REFERENCES files(id),
    person_id INT REFERENCES people(id),
    role      TEXT,   -- viewer | editor
    PRIMARY KEY (file_id, person_id)
);

CREATE TABLE sharing_events (
    id         INT PRIMARY KEY,
    file_id    INT REFERENCES files(id),
    person_id  INT REFERENCES people(id),
    action     TEXT,   -- granted | revoked
    at         DATE
);
